mapper.select:
SELECT A.ID, A.PARENT_ID, A.STORAGE_YARD_NM, A.SHORT_CD, A.AREA, A.STORAGE_YARD_TYPE_CD, B.DICT_LABEL STORAGE_YARD_TYPE_NM, A.IS_INNER_STORAGE_YARD, CASE A.IS_INNER_STORAGE_YARD WHEN '1' THEN '是' WHEN '0' THEN '否' ELSE '' END AS IS_INNER_STORAGE_YARD_LABEL, A.UNIT_AREA_TON, A.IS_RENT, A.IS_FRONTIER, CASE A.IS_RENT WHEN '1' THEN '是' WHEN '0' THEN '否' ELSE '' END AS IS_RENT_LABEL, CASE A.IS_FRONTIER WHEN '1' THEN '是' WHEN '0' THEN '否' ELSE '' END AS IS_FRONTIER_LABEL, A.WORK_AREA_CD, C.DICT_LABEL WORK_AREA_NM, A.SORT_NUM, A.STORAGE_YARD_LEVEL, CASE WHEN (SELECT COUNT(B.ID) FROM M_STORAGE_YARD B WHERE B.PARENT_ID = A.ID) > 0 THEN 'TRUE' ELSE 'FALSE' END AS HAS_CHILDREN, A.IS_BONDED_AREA, CASE A.IS_BONDED_AREA WHEN '1' THEN '是' ELSE '否' END IS_BONDED_AREA_LABEL, A.POSITION_NAME FROM M_STORAGE_YARD A LEFT JOIN M_DICT_DATA B ON B.DICT_VALUE = A.STORAGE_YARD_TYPE_CD AND B.DICT_TYPE = 'STORAGE_YARD_TYPE' LEFT JOIN M_DICT_DATA C ON C.DICT_VALUE = A.WORK_AREA_CD AND C.DICT_TYPE = 'WORK_AREA'
PARENT_ID = #{parentId}
ORDER BY A.SORT_NUM ASC

SELECT M.ID, M.BHT_ID, N.BHT_ID as PARENT_BHT_ID, N.STORAGE_YARD_NM as PARENT_NM, M.PARENT_ID, M.STORAGE_YARD_NM, M.SHORT_CD, M.AREA, M.STORAGE_YARD_TYPE_CD, M.IS_INNER_STORAGE_YARD, M.UNIT_AREA_TON, M.IS_RENT, M.WORK_AREA_CD, M.SORT_NUM, M.STORAGE_YARD_LEVEL, M.CREATE_BY, M.CREATE_BY_NAME, M.CREATE_TIME FROM M_STORAGE_YARD M INNER JOIN M_STORAGE_YARD N ON M.PARENT_ID = N.ID
N.STORAGE_YARD_LEVEL !=3 AND M.STORAGE_YARD_LEVEL !=3
AND M.BHT_ID = #{bhtId,jdbcType=BIGINT}
AND N.BHT_ID = #{parentBhtId,jdbcType=BIGINT}
AND N.STORAGE_YARD_NM = #{parentNm,jdbcType=BIGINT}
AND M.PARENT_ID = #{parentId,jdbcType=BIGINT}
AND (M.STORAGE_YARD_NM LIKE #{storageYardNm,jdbcType=VARCHAR})
